solution: ```class Solution {
public:
    int primePalindrome(int n) {
        auto isPrime = [](int x) -> bool {
            if (x < 2) return false;
            if (x % 2 == 0) return x == 2;
            for (int d = 3; d * d <= x; d += 2)
                if (x % d == 0) return false;
            return true;
        };
        auto nextPalindrome = [](int x) -> int {
            string s = to_string(x);
            int len = s.size();
            int half = (len + 1) / 2;
            string left = s.substr(0, half);
            long prefix = stol(left);
            for (int inc = 0; inc < 2; ++inc) {
                string newLeft = to_string(prefix + inc);
                string right(newLeft.rbegin() + (len % 2), newLeft.rend());
                string candidateStr = newLeft + right;
                long candidate = stol(candidateStr);
                if (candidate >= x) return (int)candidate;
            }
            return (int)pow(10, len) + 1;
        };
        int x = n;
        while (true) {
            if (x >= 10000000 && x <= 99999999) x = 100000000;
            int p = nextPalindrome(x);
            if (isPrime(p)) return p;
            x = p + 1;
        }
    }
};
